&reftitle.description;
public ReflectionFunction::__construct Closurestringfunction
Erzeugt ein ReflectionFunction-Objekt.

&reftitle.parameters;




   function



     Der Name der zu reflektierenden Funktion oder eine Closure.

&reftitle.errors;


 Eine ReflectionException, wenn der Parameter
 function keine gültige Funktion enthält.

  &reftitle.examples;



    ReflectionFunction::__construct-Beispiel


<?php
/**
 * Ein einfacher Zähler
 *
 * @return    int
 */
function counter1()
{
    static $c = 0;
    return ++$c;
}

/**
 * Ein weiterer einfacher Zähler
 *
 * @return    int
 */
$counter2 = function()
{
    static $d = 0;
    return ++$d;

};

function dumpReflectionFunction($func)
{
    // Grundlegende Informationen ausgeben
    printf(
        "\n\n===> The %s function '%s'\n".
        "     declared in %s\n".
        "     lines %d to %d\n",
        $func->isInternal() ? 'internal' : 'user-defined',
        $func->getName(),
        $func->getFileName(),
        $func->getStartLine(),
        $func->getEndline()
    );

    // Dokumentationskommentar ausgeben
    printf("---> Documentation:\n %s\n", var_export($func->getDocComment(), true));

    // Statische Variablen ausgeben, falls vorhanden
    if ($statics = $func->getStaticVariables())
    {
        printf("---> Static variables: %s\n", var_export($statics, true));
    }
}

// Eine Instanz der Klasse ReflectionFunction erzeugen
dumpReflectionFunction(new ReflectionFunction('counter1'));
dumpReflectionFunction(new ReflectionFunction($counter2));
?>


